class student_profile {
private:  
    std::string legal_name;  
    int unique_id;  
    double gpa;  

public:  
    student_profile(const std::string& name, int id, double gpa) :  
        legal_name(name), unique_id(id), gpa(gpa) {}

    std::string get_legal_name() const { return legal_name; }  
    int get_unique_id() const { return unique_id; }  
    double get_gpa() const { return gpa; }

    void print_profile() const {
        std::cout << "Legal Name: " << legal_name << std::endl;  
        std::cout << "Unique ID: " << unique_id << std::endl;  
        std::cout << "GPA: " << gpa << std::endl;  
    }
};
